const b = $input.first().json;
const phone = (b.phone || '').replace(/[^0-9+]/g, '');
const normalised = phone.startsWith('+') ? phone : '+91' + phone.replace(/^0/, '');
const amountPaise = Math.round((b.amount_inr || 0) * 100);
const expiryMins = b.expiry_mins || 60;
const expireBy = Math.floor(Date.now() / 1000) + (expiryMins * 60);

return [{
  json: {
    phone: normalised,
    amount_paise: amountPaise,
    amount_inr: b.amount_inr,
    description: b.description || 'Booking advance',
    expire_by: expireBy,
    expiry_mins: expiryMins,
    razorpay_key: process.env.RAZORPAY_KEY_ID || ''
  }
}];

const link = $input.first().json;
const prep = $('Prepare Payment').first().json;

const payUrl = link.short_url || link.payment_link_url || '';
const msg_ta = `${prep.description} க்கு ₹${prep.amount_inr} payment link: ${payUrl} — இந்த link ${prep.expiry_mins} நிமிடங்களுக்கு மட்டும் valid.`;
const msg_en = `Payment link for ${prep.description}: ₹${prep.amount_inr} — ${payUrl} (valid ${prep.expiry_mins} mins)`;

return [{
  json: {
    status: 'sent',
    payment_link: payUrl,
    payment_link_id: link.id || '',
    amount_inr: prep.amount_inr,
    phone: prep.phone,
    message_ta: msg_ta,
    message_en: msg_en
  }
}];
